  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.TaskResult;
  import sailpoint.tools.Util;
  import sailpoint.object.Application;
  import java.io.BufferedReader;
  import java.io.InputStreamReader;
  import org.apache.http.HttpResponse;
  import org.apache.http.NameValuePair;
  import org.apache.http.client.HttpClient;
  import org.apache.http.client.entity.UrlEncodedFormEntity;
  import org.apache.http.client.methods.HttpGet;
  import org.apache.http.client.methods.HttpPost;
  import org.apache.http.impl.client.DefaultHttpClient;
  import org.apache.http.message.BasicNameValuePair;
  import org.json.simple.JSONObject;
  import org.json.simple.parser.JSONParser;
  import sailpoint.tools.GeneralException;
  import org.apache.log4j.Logger;
  import org.apache.log4j.Level;
  import org.json.simple.JSONArray; 
  import java.text.SimpleDateFormat;
  import java.util.Date;
  import sailpoint.task.TaskMonitor;


  public generateToken(){

    Logger loggerForToken = Logger.getLogger("sailpoint.ascension.rules.gsuite.initilizeattributes");

    Application application = context.getObjectByName(Application.class, "GSuite");

    String tokenURL = "https://www.googleapis.com/oauth2/v3/token";

    String clientID = application.getAttributeValue("clientID").toString();
    String clientSecret = context.decrypt(application.getAttributeValue("clientSecret").toString());
    String refreshToken = context.decrypt(application.getAttributeValue("refreshToken").toString());
    String gType="refresh_token";
    URL accessTokenURL = new URL(tokenURL);
    HttpURLConnection tokenConn = (HttpURLConnection) accessTokenURL.openConnection();
    tokenConn.setDoOutput(true);
    tokenConn.setRequestMethod("POST");
    tokenConn.setRequestProperty("Content-Type", "application/json");
    String inputToken = "{\r\n \"refresh_token\":\""+ refreshToken +"\",  \r\n \"client_id\":\""+ clientID +"\",\r\n \"client_secret\":\""+ clientSecret +"\",\r\n \"grant_type\":\""+ gType + "\"}";
    //return inputToken;
    loggerForToken.debug("Access Request : "+ inputToken);
    OutputStream os = tokenConn.getOutputStream();
    os.write(inputToken.getBytes());
    os.flush();
    loggerForToken.info("Access Response : "+ tokenConn.getResponseCode());

    if(tokenConn.getResponseCode()==200){
      BufferedReader br = new BufferedReader(new InputStreamReader(tokenConn.getInputStream()));
      String out = "";
      String line ="";

      while ((line = br.readLine()) != null) {
        out=out+line;
      }
	  br.close();
      JSONParser parser = new JSONParser();
      JSONObject jobj = (JSONObject) parser.parse(out);
      // return jobj;

      if (jobj != null && jobj.get("access_token") != null) {

        global.jobj = context.encrypt(jobj.get("access_token"));

      }

    } else {

      loggerForToken.error("Failed : HTTP error code : " + tokenConn.getResponseCode());
      loggerForToken.error("Failed : HTTP error message : " + tokenConn.getResponseMessage());

    }
  }

  /* Handle Account Lookups and License Revocations */
  void updateProgress(String progressInfo){
    monitor.reattach(taskResult); 

    monitor.forceProgress(progressInfo);
  }
  TaskMonitor monitor = new TaskMonitor(context, taskResult);
  generateToken();
  int count=0;
  int countValue=0;


  List primaryEmails = executeJSONCall("/CWR/NoMail");

  int totalConsidered = primaryEmails.size();
  int totalHasLicense = 0;
  int totalNoLicense = 0;
  int totalFailedLookups = 0;
  int totalRevocations = 0;
  int totalRefusedRevocations = 0;
  int i = 0;

  List revocations = new ArrayList();

  for (String primaryEmail : primaryEmails) {
    /* count=count+1;
    if(count>=countValue){
      countValue=count+10;*/
    // generateToken();
    // }
    generateToken();
    String check = hasGSuiteLicense(primaryEmail);

    Thread.sleep(500); //Throttle API calls by half a second to avoid 403 response.

    if (Util.nullSafeCaseInsensitiveEq(check, "HasLicense")) {

      totalHasLicense++;

      String revoke = revokeGSuiteLicense(primaryEmail);

      //Thread.sleep(500); //Throttle API calls by half a second to avoid 403 response.

      if (!Util.nullSafeCaseInsensitiveEq(revoke, "NoLicense") && !Util.nullSafeCaseInsensitiveEq(revoke, "UnableToRemoveLicense")) {

        totalRevocations++;

        revocations.add(primaryEmail);

      } else if (Util.nullSafeCaseInsensitiveEq(revoke, "UnableToRemoveLicense")) {

        totalRefusedRevocations++;

      }

    } else if (Util.nullSafeCaseInsensitiveEq(check, "NoLicense")) {

      totalNoLicense++;

    } else if (Util.nullSafeCaseInsensitiveEq(check, "Forbidden")) {

      totalFailedLookups++;

    }
    if ((i % 100) == 0){
      updateProgress(String.format("Running: %d", i));
    }

  }

  /* Send Email to Collaboration */

  Calendar cal = Calendar.getInstance();

  EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-GSuite-CWRNoMail-LicenseRevocation");

  EmailOptions emailOptions = new EmailOptions();
  emailOptions.setTo("GSuiteCWRNoMailLicenseRevocation@ascension.org");

  emailOptions.setVariable("revocations", revocations);
  emailOptions.setVariable("nowDate", cal.getTime());
  emailOptions.setVariable("totalConsidered", totalConsidered);
  emailOptions.setVariable("totalHasLicense", totalHasLicense);
  emailOptions.setVariable("totalNoLicense", totalNoLicense);
  emailOptions.setVariable("totalFailedLookups", totalFailedLookups);
  emailOptions.setVariable("totalRevocations", totalRevocations);
  emailOptions.setVariable("totalRefusedRevocations", totalRefusedRevocations);

  if (emailTemplate != null && emailOptions != null) {

    context.sendEmailNotification(emailTemplate, emailOptions);

  }

  /* Update TaskResult with Metrics */

  taskResult.addAttribute("Total Accounts Considered", totalConsidered);
  taskResult.addAttribute("Total With License", totalHasLicense);
  taskResult.addAttribute("Total Without License", totalNoLicense);
  taskResult.addAttribute("Total Failed Lookups [403 Forbidden]", totalFailedLookups);
  taskResult.addAttribute("Total Successful Revocations", totalRevocations);
  taskResult.addAttribute("Total Refused Revocations [412 Precondition Failed]", totalRefusedRevocations);
